import React, { useState } from "react";
import RegisterStudent from "./components/RegisterStudent";
import TakeAttendance from "./components/TakeAttendance";
import StudentList from "./components/StudentList";
import AttendanceLog from "./components/AttendanceLog";
import { Toaster } from "react-hot-toast";
import "./App.css";

const NAV = [
  { id: "register",   label: "Register Student", icon: "👤" },
  { id: "attendance", label: "Take Attendance",   icon: "📸" },
  { id: "students",   label: "Students",          icon: "🎓" },
  { id: "log",        label: "Attendance Log",    icon: "📋" },
];

export default function App() {
  const [active, setActive] = useState("register");

  return (
    <div className="app">
      <Toaster position="top-right" toastOptions={{ duration: 3500 }} />

      <aside className="sidebar">
        <div className="sidebar-brand">
          <div className="brand-icon">🎓</div>
          <div>
            <div className="brand-name">FaceTrack</div>
            <div className="brand-sub">Attendance System</div>
          </div>
        </div>

        <nav className="sidebar-nav">
          {NAV.map((item) => (
            <button
              key={item.id}
              className={`nav-item ${active === item.id ? "active" : ""}`}
              onClick={() => setActive(item.id)}
            >
              <span className="nav-icon">{item.icon}</span>
              <span className="nav-label">{item.label}</span>
              {active === item.id && <span className="nav-indicator" />}
            </button>
          ))}
        </nav>

        <div className="sidebar-footer">
          <div className="status-dot" />
          <span>System Online</span>
        </div>
      </aside>

      <main className="main-content">
        <div className="page-header">
          <div className="page-title">
            <span className="page-icon">{NAV.find(n => n.id === active)?.icon}</span>
            {NAV.find(n => n.id === active)?.label}
          </div>
          <div className="page-date">
            {new Date().toLocaleDateString("en-US", {
              weekday: "long", year: "numeric", month: "long", day: "numeric",
            })}
          </div>
        </div>

        <div className="page-body">
          {active === "register"   && <RegisterStudent />}
          {active === "attendance" && <TakeAttendance />}
          {active === "students"   && <StudentList />}
          {active === "log"        && <AttendanceLog />}
        </div>
      </main>
    </div>
  );
}
